/*
 * Minimal offline HTMX-compatible adapter for the FastAPI/Jinja worksheet.
 * It implements only the local form behavior this app uses: hx-post,
 * hx-target, hx-swap, change/key triggers, and textarea target updates.
 */

(() => {
  const debounce = (callback, delayMs) => {
    let timeoutId = null;
    return (...args) => {
      window.clearTimeout(timeoutId);
      timeoutId = window.setTimeout(() => callback(...args), delayMs);
    };
  };

  const updateTarget = (target, text, swapMode) => {
    if (target instanceof HTMLTextAreaElement || target instanceof HTMLInputElement) {
      target.value = text;
      return;
    }
    if (swapMode === "outerHTML") {
      target.outerHTML = text;
      return;
    }
    target.innerHTML = text;
  };

  const submitForm = async form => {
    const postUrl = form.getAttribute("hx-post");
    const targetSelector = form.getAttribute("hx-target");
    if (!postUrl || !targetSelector) return;

    const target = document.querySelector(targetSelector);
    if (!target) return;

    const response = await fetch(postUrl, {
      method: "POST",
      body: new FormData(form),
      headers: { "HX-Request": "true" },
    });
    updateTarget(target, await response.text(), form.getAttribute("hx-swap"));
  };

  const attach = () => {
    document.querySelectorAll("form[hx-post]").forEach(form => {
      if (form.dataset.localHtmxBound === "true") return;
      form.dataset.localHtmxBound = "true";

      const debouncedSubmit = debounce(() => submitForm(form), 300);
      form.addEventListener("change", debouncedSubmit);
      form.addEventListener("keyup", debouncedSubmit);
      form.addEventListener("submit", event => {
        event.preventDefault();
        submitForm(form);
      });
    });
  };

  window.htmx = {
    version: "local-offline-adapter",
    process: attach,
  };

  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", attach);
  } else {
    attach();
  }
})();
